// frontend/src/pages/Sales/SaleList.jsx
import { useCallback, useEffect, useMemo, useState } from "react";
import { Link, useNavigate } from "react-router-dom";
import { deleteSale, getSales, getSalesStats } from "../../api/saleApi";
import { getAuth } from "../../utils/auth";

export default function SaleList() {
  const [sales, setSales] = useState([]);
  const [stats, setStats] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  const navigate = useNavigate();
  const { role } = getAuth();
  const canManage = role === "admin" || role === "manager";
  const year = new Date().getFullYear();

  const revenueOf = (s) => Number(s.finalPrice ?? s.quotedPrice ?? 0);
  const isCompleted = (s) => s.dealStatus === "completed" || s.paymentStatus === "completed";

  const load = useCallback(async () => {
    setError("");
    setLoading(true);
    try {
      const [salesRes, statsRes] = await Promise.all([
        getSales(),
        getSalesStats(year),
      ]);
      setSales(salesRes.data || []);
      setStats(statsRes.data || null);
    } catch (err) {
      setError(err.response?.data?.message || "Failed to load sales");
      setSales([]);
      setStats(null);
    } finally {
      setLoading(false);
    }
  }, [year]);

  useEffect(() => {
    load();
  }, [load]);

  // fallback if stats fails
  const fallback = useMemo(() => {
    const completed = sales.filter(isCompleted);
    const totalRevenue = completed.reduce((sum, s) => sum + revenueOf(s), 0);

    const months = new Set(
      completed.map((s) => {
        const d = new Date(s.createdAt);
        return `${d.getFullYear()}-${d.getMonth() + 1}`;
      })
    );

    const avgMonthlyRevenue = months.size ? totalRevenue / months.size : 0;

    return { totalRevenue, totalSales: completed.length, avgMonthlyRevenue };
  }, [sales]);

  const totalRevenue = stats?.totalRevenue ?? fallback.totalRevenue;
  const totalSales = stats?.totalSales ?? fallback.totalSales;
  const avgMonthlyRevenue = stats?.avgMonthlyRevenue ?? fallback.avgMonthlyRevenue;

  const onDelete = async (id) => {
    if (!canManage) return alert("Access denied");
    if (!window.confirm("Delete this sale record?")) return;

    try {
      await deleteSale(id);
      await load();
    } catch (err) {
      alert(err.response?.data?.message || "Delete failed");
    }
  };

  return (
    <div style={{ padding: 20 }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
        <h2 style={{ margin: 0 }}>Sales</h2>
        <div style={{ display: "flex", gap: 10 }}>
          <button onClick={load} disabled={loading}>{loading ? "Loading..." : "Refresh"}</button>
          {canManage && (
            <Link to="/sales/add"><button>+ Add Sale</button></Link>
          )}
        </div>
      </div>

      {error && (
        <div style={{ marginTop: 12, padding: 10, border: "1px solid #fca5a5", borderRadius: 8 }}>
          <b>Error:</b> {error}
        </div>
      )}

      {/* Stats */}
      <div style={{ marginTop: 14, border: "1px solid #ddd", borderRadius: 10, padding: 14 }}>
        <div style={{ display: "flex", gap: 20, flexWrap: "wrap" }}>
          <div>
            <div style={{ fontSize: 12, opacity: 0.7 }}>Total Revenue ({year})</div>
            <div style={{ fontSize: 22, fontWeight: 700 }}>
              Rs. {Number(totalRevenue || 0).toLocaleString()}
            </div>
          </div>

          <div>
            <div style={{ fontSize: 12, opacity: 0.7 }}>Monthly Average Revenue</div>
            <div style={{ fontSize: 22, fontWeight: 700 }}>
              Rs. {Number(avgMonthlyRevenue || 0).toLocaleString()}
            </div>
          </div>

          <div>
            <div style={{ fontSize: 12, opacity: 0.7 }}>Completed Sales Count</div>
            <div style={{ fontSize: 22, fontWeight: 700 }}>
              {Number(totalSales || 0)}
            </div>
          </div>
        </div>
      </div>

      {/* List */}
      <table border="1" cellPadding="10" style={{ width: "100%", marginTop: 14, textAlign: "left" }}>
        <thead>
          <tr>
            <th>Vehicle</th>
            <th>Customer</th>
            <th>Revenue</th>
            <th>Payment Status</th>
            <th>Deal Status</th>
            <th>Date</th>
            <th style={{ width: 220 }}>Actions</th>
          </tr>
        </thead>
        <tbody>
          {loading && (
            <tr><td colSpan="7">Loading...</td></tr>
          )}

          {!loading && sales.map((s) => (
            <tr key={s._id}>
              <td>
                {s.vehicle?.brand
                  ? `${s.vehicle.brand} ${s.vehicle.model || s.vehicle.type || ""}`
                  : "-"}
              </td>
              <td>{s.customer?.name || "-"}</td>
              <td>Rs. {revenueOf(s).toLocaleString()}</td>
              <td>{s.paymentStatus || "-"}</td>
              <td>{s.dealStatus || "-"}</td>
              <td>{s.createdAt ? new Date(s.createdAt).toLocaleDateString() : "-"}</td>
              <td>
                {canManage ? (
                  <>
                    <button onClick={() => navigate(`/sales/edit-payment/${s._id}`)}>Edit</button>
                    <button style={{ marginLeft: 6 }} onClick={() => onDelete(s._id)}>Delete</button>
                  </>
                ) : "-"}
              </td>
            </tr>
          ))}

          {!loading && sales.length === 0 && (
            <tr><td colSpan="7">No sales found</td></tr>
          )}
        </tbody>
      </table>
    </div>
  );
}
